// Load all configuration from variables
const config = {
  // Cost Configuration
  cost_uzs: {
    agent_hourly_rate: parseInt($vars.AGENT_HOURLY_RATE) || 50000,
    manual_ticket_cost: parseInt($vars.MANUAL_TICKET_COST) || 12500,
    ai_processing_cost: parseInt($vars.AI_PROCESSING_COST) || 2500,
    savings_per_ticket: parseInt($vars.SAVINGS_PER_TICKET) || 10000,
    tickets_per_month: parseInt($vars.TICKETS_PER_MONTH) || 1000
  },

  // AI Configuration
  ai_config: {
    model: "openai/gpt-4o-mini",
    timeout_ms: 6000,
    retry_count: 3,
    confidence_threshold: 0.7
  },

  // SLA Configuration
  uzbekistan_sla: {
    timezone: 'Asia/Tashkent',
    business_hours: { start: 9, end: 18, days: [1, 2, 3, 4, 5] },
    thresholds_ms: { critical: 1800000, high: 7200000, medium: 28800000, low: 86400000 },
    after_hours_multiplier: 1.5
  },

  // System Configuration
  system_config: {
    workflow_version: 'Revenant_v20_HYBRID_ENTERPRISE',
    max_tickets_per_minute: 100,
    audit_log_enabled: true,
    telemetry_enabled: true,
    // ✅ ADDED: Initialize memory retrieval failure counter
    memory_retrieval_failures: 0
  }
};

// Validate configuration
const validation = {
  has_cost_config: !!config.cost_uzs,
  has_ai_config: !!config.ai_config,
  variables_loaded: {
    AGENT_HOURLY_RATE: !!$vars.AGENT_HOURLY_RATE,
    MANUAL_TICKET_COST: !!$vars.MANUAL_TICKET_COST,
    AI_PROCESSING_COST: !!$vars.AI_PROCESSING_COST,
    SAVINGS_PER_TICKET: !!$vars.SAVINGS_PER_TICKET,
    TICKETS_PER_MONTH: !!$vars.TICKETS_PER_MONTH
  }
};

const outputItem = {
  json: {
    config: config,
    config_validation: validation,
    loaded_at: new Date().toISOString(),
    node_count: Object.keys($node || {}).length
  }
};

// ✅ EXECUTION IDENTITY - ADDED AT END FOR MERGE DETERMINISM
outputItem.json.trace_id = $execution.id;

return [outputItem];

const item = $input.first();
const ct = item.json.canonical_ticket;

// Phase 0 Core Validation - HARDENED FOR TYPE SAFETY
const errors = [];

// 1. REQUIRED: Trace ID must exist and be valid
if (!ct.trace_id) {
  errors.push('MISSING_TRACE_ID');
} else {
  // Convert to string safely for validation
  const traceIdStr = String(ct.trace_id);
  if (traceIdStr.trim().length === 0) {
    errors.push('EMPTY_TRACE_ID');
  }
}

// 2. REQUIRED: Subject must exist and be valid length
if (!ct.subject) {
  errors.push('MISSING_SUBJECT');
} else {
  const subjectStr = String(ct.subject);
  if (subjectStr.trim().length === 0) {
    errors.push('EMPTY_SUBJECT');
  } else if (subjectStr.trim().length > 500) {
    errors.push('SUBJECT_TOO_LONG');
  }
}

// 3. REQUIRED: Valid email format
if (!ct.customer_email) {
  errors.push('MISSING_CUSTOMER_EMAIL');
} else {
  const emailStr = String(ct.customer_email);
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailStr)) {
    errors.push('INVALID_CUSTOMER_EMAIL_FORMAT');
  }
}

// 4. SANITY: workflow_error shouldn't exist yet
if (ct.workflow_error) {
  errors.push('PREMATURE_WORKFLOW_ERROR');
}

// 5. ✅ CORRECTED: language_analysis is NOT required at this stage
//    This validation was premature - removing requirement

// 6. ✅ CORRECTED: rule_engine is NOT required at this stage  
//    This validation was premature - removing requirement

// VALIDATION RESULT
if (errors.length > 0) {
  return [{
    json: {
      canonical_ticket: {
        ...ct,
        workflow_error: {
          type: 'PHASE_0_VALIDATION_FAILED',
          errors: errors,
          timestamp: new Date().toISOString(),
          trace_id: String(ct.trace_id || 'UNKNOWN'),  // Convert to string
          stage: 'phase_0_validation',
          input_sample: {
            subject: ct.subject ? String(ct.subject).substring(0, 50) : 'missing',
            email: ct.customer_email ? String(ct.customer_email) : 'missing'
          }
        },
        __validation_failed: true
      }
    }
  }];
}

// ✅ PHASE 0 COMPLETE - Continue normally
return [{
  json: {
    trace_id: String(ct.trace_id) ,
    canonical_ticket: {
      ...ct,
      // Ensure trace_id is string for downstream consistency
      trace_id: String(ct.trace_id),
      // Add Phase 0 validation timestamp
      phase_0_completed_at: new Date().toISOString(),
      phase_0_status: 'validated'
    }
  }
}];

// Input Validator & Cleaner - V16 - HARDENED
const envelope = $input.first().json;

// ARCHITECTURAL GUARD - Must have envelope structure
if (!envelope.meta || envelope.meta.stage !== 'SB0') {
  throw new Error(`ARCHITECTURAL_VIOLATION: Invalid envelope stage - expected SB0, got ${envelope.meta?.stage}`);
}

const payload = envelope.payload;

// Validate required fields exist
const requiredFields = ['subject', 'body', 'customer_email'];
const missingFields = requiredFields.filter(field => !payload?.[field]);
if (missingFields.length > 0) {
  throw new Error(`SB1_VALIDATION_FAILED: Missing payload fields: ${missingFields.join(', ')}`);
}

// Clean text function
const cleanText = (text) => {
  if (!text) return '';
  return text.toString()
    .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
    .replace(/<[^>]*>/g, '')
    .replace(/[&<>"']/g, char => ({
      '&': '&amp;',
      '<': '&lt;', 
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#x27;'
    }[char]))
    .replace(/[\t\n\r]+/g, ' ')
    .trim();
};

// Extract headers from envelope (preserved in SB0 envelope)
const originalHeaders = envelope.original_headers || {};

// Build canonical ticket with SINGULARITY FLAG
const cleaned_ticket = {
  trace_id: envelope.meta.trace_id,
  subject: cleanText(payload.subject),
  body: cleanText(payload.body),
  customer_email: cleanText(payload.customer_email),
  original_subject: payload.subject,
  original_body: payload.body,
  original_customer_email: payload.customer_email,
  severity: payload.severity || 'medium',
  priority: payload.priority || 'medium',
  category: payload.category || 'technical',
  webhook_received_at: new Date().toISOString(),
  client_ip: originalHeaders['x-forwarded-for'] || 'unknown',
  user_agent: originalHeaders['user-agent'] || 'unknown',
  // ⚡ CRITICAL SINGULARITY FLAG - Prevents re-validation
  __validation_attempted: true,
  // Audit trail
  validation_stage: 'SB1',
  envelope_processed_at: envelope.meta?.timestamp || new Date().toISOString()
};

return [{
  json: {
    canonical_ticket: cleaned_ticket,
    // Preserve envelope metadata for traceability
    __envelope_metadata: {
      trace_id: envelope.meta.trace_id,
      stage: envelope.meta.stage,
      execution_mode: envelope.meta.execution_mode,
      processed_at: new Date().toISOString()
    }
  }
}];

// ⚠️ SB1 ERROR EXIT – Validation Failure Handler - TERMINAL
const item = $input.first();

// TERMINAL ERROR - Structured for webhook response
return [{
  json: {
    // Signal to Return Validation Error node that this is a terminal error
    __terminal_error: true,
    error_type: 'SB1_VALIDATION_TERMINAL',
    trace_id: item.json.meta?.trace_id || 'unknown',
    stage: 'SB1',
    http_code: 400,
    reason: 'Validation failed – terminal exit',
    timestamp: new Date().toISOString(),

    // Preserve envelope structure for audit trail
    original_envelope: {
      meta: item.json.meta,
      config: item.json.config,
      payload: item.json.payload
    }
  }
}];

// PROD Input Normalizer - Hardened V20
const item = $input.first();
const json = item.json;

// 1. CANONICAL TRACE ID - ADDED AT TOP FOR DETERMINISM
item.json.trace_id = $execution.id;

// 2. EXISTING NORMALIZATION LOGIC
if (json.subject && json.body && !json.body?.subject) {
  return [{
    json: {
      trace_id: $execution.id, // Preserve in normalized structure
      body: {
        subject: json.subject,
        body: json.body,
        customer_email: json.customer_email || null
      }
    }
  }];
}

// 3. ENSURE TRACE_ID PERSISTS IN ALL RETURN PATHS
return [{ 
  json: {
    ...json,
    trace_id: $execution.id // Force overwrite to prevent any upstream contamination
  }
}];

const item = $input.first();
const ct = item.json.canonical_ticket;
const text = (ct.subject + ' ' + ct.body).toLowerCase();

const rules = [
  { intent: 'vpn_issue', regex: /\b(vpn|ulanish|tarmo[gq]|connect|сеть|подключение)\b/, severity: 'medium', score: 1.0 },
  { intent: 'password_reset', regex: /\b(parol|password|логин|пароль|reset|сброс|hisob|account)\b/, severity: 'medium', score: 1.0 },
  { intent: 'network_issue', regex: /\b(internet|сеть|подключение|network|slow|медленно|tarmoq)\b/, severity: 'high', score: 1.0 },
  { intent: 'software_install', regex: /\b(dastur|программа|software|установка|o'rnatish|instal|yuklash)\b/, severity: 'medium', score: 0.9 },
  { intent: 'hardware_issue', regex: /\b(kompyuter|computer|компьютер|noutbuk|ноутбук|printer|принтер|hardware|qurilma)\b/, severity: 'medium', score: 0.9 },
  { intent: 'email_issue', regex: /\b(email|почта|elektron pochta|message|xat|gmail|outlook)\b/, severity: 'low', score: 0.8 },
  { intent: 'security_alert', regex: /\b(security|xavfsizlik|безопасность|hacker|hack|virus|вирус|attack)\b/, severity: 'critical', score: 1.0 }
];

let detectedIntent = 'general_inquiry';
let detectedSeverity = ct.severity || 'medium';
let ruleConfidence = 0.5;

for (const rule of rules) {
  if (rule.regex.test(text)) {
    detectedIntent = rule.intent;
    detectedSeverity = rule.severity;
    ruleConfidence = rule.score;
    break;
  }
}

return [{
  json: {
    canonical_ticket: {
      ...ct,
      rule_engine: {
        intent: detectedIntent,
        severity: detectedSeverity,
        confidence: ruleConfidence,
        detected_at: new Date().toISOString()
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

// Deterministic Severity Classification
const item = $input.first();
const ct = item.json.canonical_ticket || item.json;
const text = ct.subject + ' ' + ct.body;
const textLower = text.toLowerCase();

// Use text features if available
const textFeatures = ct.text_features || item.json.text_features || {};

// Scoring system
const scores = { critical: 0, high: 0, medium: 0, low: 0 };

// Critical indicators
const criticalTerms = ['critical', 'emergency', 'outage', 'down', 'breach', 'data loss'];
criticalTerms.forEach(term => {
  if (textLower.includes(term)) scores.critical += 3;
});

// High severity indicators  
const highTerms = ['urgent', 'failed', 'cannot', 'unable', 'revenue', 'customer'];
highTerms.forEach(term => {
  if (textLower.includes(term)) scores.high += 2;
});

// Medium severity indicators
const mediumTerms = ['issue', 'problem', 'help', 'support', 'slow'];
mediumTerms.forEach(term => {
  if (textLower.includes(term)) scores.medium += 1;
});

// Text statistics boost
if (textFeatures.total_length > 200) scores.high += 1;
if (textFeatures.has_urgent) scores.high += 1;
if (textFeatures.has_critical) scores.critical += 2;

// Determine severity
const maxScore = Math.max(...Object.values(scores));
let severity = 'medium';
let confidence = 0.5;

if (maxScore > 0) {
  if (scores.critical >= 3) severity = 'critical';
  else if (scores.high >= 2) severity = 'high';
  else if (scores.medium >= 1) severity = 'medium';
  else severity = 'low';

  confidence = Math.min(0.5 + (maxScore / 10), 0.95);
}

return [{
  json: {
    ...item.json,
    rule_based_severity: {
      severity,
      confidence,
      scores
    },
    canonical_ticket: {
      ...ct,
      rule_based_severity: {
        severity,
        confidence,
        scores
      }
    }
  }
}];

// Text Feature Engineering (Deterministic) - V20
const item = $input.first();
const ct = item.json.canonical_ticket;

// Validate input has required fields
if (!ct.trace_id || !ct.subject || !ct.body) {
  throw new Error(`MISSING_REQUIRED_FIELDS: trace_id=${!!ct.trace_id}, subject=${!!ct.subject}, body=${!!ct.body}`);
}

const text = (ct.subject || '') + ' ' + (ct.body || '');
const textLower = text.toLowerCase();

// Length features
const features = {
  subject_length: ct.subject?.length || 0,
  body_length: ct.body?.length || 0,
  total_length: text.length,
  word_count: text.split(/\s+/).filter(w => w).length
};

// Keyword detection
features.has_critical = /\b(critical|emergency|outage|down|breach)\b/i.test(text);
features.has_urgent = /\b(urgent|immediate|asap|now)\b/i.test(text);
features.has_error_code = /error\s+\d+|code\s+\d+|err\s+\d+/i.test(text);
features.has_question = /\b(how|what|why|can|could|would)\b/i.test(text);

// Complexity score
features.complexity_score = (
  features.word_count * 0.1 +
  (features.has_critical ? 3 : 0) +
  (features.has_urgent ? 2 : 0) +
  (features.has_error_code ? 1 : 0)
);

// Update canonical ticket
const updatedTicket = {
  ...ct,
  text_features: features,
  data_integrity: {
    ...ct.data_integrity,
    last_modified: Date.now(),
    modification_count: (ct.data_integrity?.modification_count || 0) + 1
  }
};

return [{
  json: {
    canonical_ticket: updatedTicket
  }
}];

// Pre-Fusion Classification Normalizer - V20
const item = $input.first();
const ct = item.json.canonical_ticket;

// VALIDATE PREREQUISITES
if (!ct.rule_engine || !ct.rule_engine.intent) {
  throw new Error(`MISSING_RULE_ENGINE: Cannot normalize without rule engine classification`);
}

if (!ct.rule_based_severity || !ct.rule_based_severity.severity) {
  throw new Error(`MISSING_SEVERITY: Cannot normalize without rule-based severity`);
}

// DETERMINISTIC NORMALIZATION
const classification = {
  // Intent from rule engine (guaranteed)
  intent: ct.rule_engine.intent,

  // Severity hierarchy: rule_based_severity > rule_engine.severity > 'medium'
  severity: ct.rule_based_severity.severity || ct.rule_engine.severity || 'medium',

  // Confidence from rule engine (deterministic)
  confidence: ct.rule_engine.confidence || 0.5,

  // Source identification
  source: 'rule_engine',

  // Timestamp
  normalized_at: new Date().toISOString(),

  // Provenance
  provenance: {
    rule_engine: {
      intent: ct.rule_engine.intent,
      confidence: ct.rule_engine.confidence,
      detected_at: ct.rule_engine.detected_at
    },
    rule_based_severity: {
      severity: ct.rule_based_severity.severity,
      confidence: ct.rule_based_severity.confidence,
      scores: ct.rule_based_severity.scores
    }
  }
};

// Update canonical ticket
const updatedTicket = {
  ...ct,
  classification: classification,
  data_integrity: {
    ...ct.data_integrity,
    last_modified: Date.now(),
    modification_count: (ct.data_integrity?.modification_count || 0) + 1,
    classification_normalized: true
  }
};

return [{
  json: {
    canonical_ticket: updatedTicket
  }
}];

const item = $input.first();
const ct = item.json.canonical_ticket || {};

// ✅ FIXED: Get cost config from canonical_ticket or use defaults
const costCfg = ct.workflow_metadata?.config?.cost_uzs || {
  agent_hourly_rate: 50000,
  manual_ticket_cost: 12500,
  ai_processing_cost: 2500,
  savings_per_ticket: 10000,
  tickets_per_month: 1000
};

const aiCost = costCfg.ai_processing_cost || 0;
const manualCost = costCfg.manual_ticket_cost || 0;
const autoResolved = ct.ticket_status === 'auto_resolved';
const cost_saved_uzs = autoResolved ? Math.max(0, manualCost - aiCost) : 0;

// Calculate ROI properly (prevent division by zero)
const roi_per_ticket = autoResolved && aiCost > 0 ? ((manualCost - aiCost) / aiCost) * 100 : 0;

return [{
  json: {
    canonical_ticket: {
      ...ct,
      business_impact: {
        ai_cost_uzs: aiCost,
        manual_cost_uzs: manualCost,
        cost_saved_uzs,
        agent_time_saved_minutes: autoResolved ? 15 : 0,
        roi_per_ticket: parseFloat(roi_per_ticket.toFixed(2)),
        // ✅ Add config source for debugging
        config_source: ct.workflow_metadata?.cost_config_used ? 'workflow_variables' : 'default'
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

const item = $input.first();
const ct = item.json.canonical_ticket;
const config = ct.workflow_metadata?.config || {};
const now = new Date().getTime();

// ✅ v20 MERGE: Correct timezone calculation for Tashkent from v18
const tashkentOffset = 5 * 60 * 60 * 1000; // UTC+5 in milliseconds
const tashkentTime = new Date(now + tashkentOffset);

// Get hour in Tashkent (0-23)
const hour = tashkentTime.getUTCHours();
const dayOfWeek = tashkentTime.getUTCDay(); // 0 = Sunday

// Business hours in Tashkent: Monday-Friday, 9:00-18:00
const isBusinessHours = dayOfWeek >= 1 && dayOfWeek <= 5 && hour >= 9 && hour < 18;

const slaConfig = config.uzbekistan_sla || {};
const baseThresholds = slaConfig.thresholds_ms || {
  critical: 1800000, high: 7200000, medium: 28800000, low: 86400000
};

const multiplier = isBusinessHours ? 1 : (slaConfig.after_hours_multiplier || 1.5);
const severity = ct.classification?.severity || 'medium';
const thresholdMs = baseThresholds[severity] * multiplier;
const deadline = new Date(now + thresholdMs);

const startTime = ct.workflow_metadata?.workflow_start_time || now;
const processingTime = Math.max(0, now - startTime);
const meetsSla = processingTime < thresholdMs;

let slaBreachLevel = 'none';
if (!meetsSla) {
  const breachMs = processingTime - thresholdMs;
  if (breachMs > 3600000) slaBreachLevel = 'critical';
  else if (breachMs > 900000) slaBreachLevel = 'major';
  else slaBreachLevel = 'minor';
}

return [{
  json: {
    canonical_ticket: {
      ...ct,
      performance_metrics: {
        total_processing_ms: processingTime,
        meets_sla: meetsSla,
        sla_threshold_ms: thresholdMs,
        sla_breach_level: slaBreachLevel,
        sla_breach_ms: meetsSla ? 0 : processingTime - thresholdMs,
        deadline_utc: deadline.toISOString(),
        uzbekistan_timezone: 'Asia/Tashkent (UTC+5, no DST)',
        current_uzbekistan_time: tashkentTime.toISOString(),
        is_business_hours: isBusinessHours,
        business_hours_range: '9:00-18:00 Tashkent time',
        day_of_week: ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'][dayOfWeek]
      },
      data_integrity: {
        ...ct.data_integrity,
        last_modified: Date.now(),
        modification_count: (ct.data_integrity?.modification_count || 0) + 1
      }
    }
  }
}];

const item = $input.first();
const text = (item.json.cleaned_ticket?.subject || '') + ' ' + (item.json.cleaned_ticket?.body || '');
const textLower = text.toLowerCase();

// ✅ v19 MERGE: Expanded Uzbek vocabulary from v18 + code-switching detection
const uzbekPatterns = [
  /\b(iltimos|rahmat|yordam|muammo|dastur|tizim|internet|kompyuter|telefon|printer|noutbuk|server)\b/i,
  /\b(parol|login|hisob|akkaunt|foydalanuvchi|admin|administrator|superadmin)\b/i,
  /\b(vpn|tarmoq|ulanish|aloqa|signal|wi[\-\s]?fi|mobil[\-\s]?internet)\b/i,
  /\b(xat|email|pochta|sms|habar|notification|bildirishnoma)\b/i,
  /\b(dasturiy|programma|software|ilova|application|mobile[\-\s]?app)\b/i,
  /\b(tezlik|speed|slow|sekin|yuklab[\s\-]olish|download|upload)\b/i,
  /\b(to'lov|payment|pul|click|payme|apelsin|kapital[\-\s]bank)\b/i,
  /\b(holat|status|jarayon|process|ishlamayapti|broken|broken)\b/i,
  /\b(yangi|new|update|yangilash|version|versiya)\b/i,
  /\b(aylantirish|transfer|o'tkazish|change|o'zgartirish|settings)\b/i
];

const russianPatterns = [
  /\b(пожалуйста|спасибо|здравствуйте|помогите|проблема|программа|сеть|интернет)\b/i,
  /\b(компьютер|ноутбук|принтер|телефон|сервер|оборудование)\b/i,
  /\b(пароль|логин|аккаунт|пользователь|админ|администратор)\b/i,
  /\b(почта|email|сообщение|письмо|уведомление)\b/i,
  /\b(скорость|медленно|з��грузка|скачать|загрузить)\b/i,
  /\b(платеж|оплата|деньги|клик|пайме|капиталбанк)\b/i
];

const englishPatterns = [
  /\b(please|thank you|help|hello|hi|support|ticket|issue)\b/i,
  /\b(computer|laptop|printer|phone|server|hardware)\b/i,
  /\b(password|login|account|user|admin|administrator)\b/i,
  /\b(email|message|mail|notification|alert)\b/i,
  /\b(speed|slow|download|upload|connection|network)\b/i,
  /\b(payment|money|pay|click|payme|capitalbank)\b/i
];

let uzbekScore = uzbekPatterns.reduce((score, pattern) => score + (pattern.test(text) ? 1 : 0), 0);
let russianScore = russianPatterns.reduce((score, pattern) => score + (pattern.test(text) ? 1 : 0), 0);
let englishScore = englishPatterns.reduce((score, pattern) => score + (pattern.test(text) ? 1 : 0), 0);

// Detect code-switching (Uzbek-Russian mix)
const hasCodeSwitching = (uzbekScore > 0 && russianScore > 0) || 
                         text.match(/[а-яА-Я].*[a-zA-Z]|[a-zA-Z].*[а-яА-Я]/);

let detected = 'en';
let confidence = 0.5;

if (uzbekScore > russianScore && uzbekScore > englishScore) {
  detected = 'uz';
  confidence = Math.min(0.95, 0.5 + (uzbekScore * 0.1));
} else if (russianScore > uzbekScore && russianScore > englishScore) {
  detected = 'ru';
  confidence = Math.min(0.95, 0.5 + (russianScore * 0.1));
} else {
  detected = 'en';
  confidence = Math.min(0.95, 0.5 + (englishScore * 0.08));
}

// Boost confidence if code-switching detected
if (hasCodeSwitching && confidence < 0.8) {
  confidence = Math.min(0.9, confidence + 0.15);
}

return [{
  json: {
    ...item.json,
    language_analysis: {
      detected,
      confidence,
      scores: { uz: uzbekScore, ru: russianScore, en: englishScore },
      requires_translation: detected !== 'en',
      code_switching_detected: hasCodeSwitching || false,
      vocabulary_matches: { uzbek: uzbekScore, russian: russianScore, english: englishScore }
    }
  }
}];

// Metrics Emitter Node - Code
const item = $input.first();
const ct = item.json.canonical_ticket || {};
const guard = ct.transition_guard || {};

// Derived metrics (idempotent - based on guard state only)
const metrics = {
  timestamp: new Date().toISOString(),
  trace_id: ct.trace_id,
