  if (guard.is_duplicate_event) return 'duplicate';
  if ((guard.blocked_reason || '').includes('oscillation')) return 'oscillation';
  if ((guard.blocked_reason || '').includes('invalid_transition')) return 'invalid_transition';
  if (guard.error) return 'validation_error';
  return 'guard_decision';
}

const forensicLog = {
