    if (!rule.jurisdiction_allowed.includes('*') && !rule.jurisdiction_allowed.includes(jurisdiction)) return false;
    return true;
  })
  .sort((a, b) => a[1].priority - b[1].priority) // Higher priority first
  .map(([channel]) => channel);

// Select highest priority eligible channel
let selected_channel = 'INTERNAL_UI';
if (eligible.includes('WEBHOOK_DELIVERY') && confidence >= 0.7 && jurisdiction !== '.uz') {
  selected_channel = 'WEBHOOK_DELIVERY';
} else if (eligible.includes('EMAIL_TEMPLATE') && confidence >= 0.4) {
  selected_channel = 'EMAIL_TEMPLATE';
}

return [{
  json: {
    ...input,
    selected_channel,
    eligible_channels: eligible,
    arbitration_reason: `Selected ${selected_channel} based on confidence ${confidence}, jurisdiction ${jurisdiction}, advisory_hash ${advisory_hash.slice(0, 16)}`,
    arbitration_timestamp: new Date().toISOString(),
    arbitration_final: true // Immutable flag
  }
}];

// SIMPLIFIED APPROVAL + REQUEST MERGER (SINGLE INPUT)
const input = $json;

if (!input.validated_approval) {
  throw new Error('MERGE_FAILED: Missing validated_approval');
}

if (!input.approval_request) {
  throw new Error('MERGE_FAILED: Missing approval_request (should come from validator)');
}

const validated_approval = input.validated_approval;
const approval_request = input.approval_request;

// Cross-validation
if (approval_request.approval_id !== validated_approval.approval_id) {
  throw new Error('MERGE_FAILED: approval_id mismatch');
}

if (approval_request.advisory_hash !== validated_approval.advisory_hash) {
  throw new Error('MERGE_FAILED: advisory_hash mismatch');
}

if (validated_approval.selected_channel !== approval_request.selected_channel) {
  throw new Error('MERGE_FAILED: Channel tampering detected');
}

const merged = {
  approval_request,
  validated_approval,
  merged_at: new Date().toISOString(),
  decision_finalized: validated_approval.decision === 'APPROVED'
};

if (validated_approval.decision === 'REJECTED') {
  merged.terminal_state = {
    type: 'REJECTED',
    approver_id: validated_approval.approver_id,
    approver_role: validated_approval.approver_role,
    timestamp: validated_approval.approval_timestamp,
    advisory_hash: validated_approval.advisory_hash,
    rejection_reason: validated_approval.rejection_reason || 'Not specified',
    selected_channel: validated_approval.selected_channel
  };
}

return [{ json: merged }];

// DATABASE-LEVEL IDEMPOTENCE LOCK
const crypto = require('crypto');
const { createClient } = require('@supabase/supabase-js');

const input = $json;
const { validated_approval, approval_request } = input;

// ---- REJECTION HANDLING
if (validated_approval.decision !== 'APPROVED') {
  return [{
    json: {
      ...input,
      dispatch_guard: {
        guard_passed: false,
        decision: 'REJECTED',
        terminal_path: true,
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// ---- CHANNEL FROM APPROVAL_REQUEST (LEDGER SOURCE OF TRUTH)
const approved_channel = approval_request.selected_channel;
if (!approved_channel) {
  throw new Error('DISPATCH_GUARD_FAILED: No channel in approval_request');
}

// ---- SUPABASE CLIENT
const supabaseUrl = $credentials.supabaseApi.supabaseUrl;
const supabaseKey = $credentials.supabaseApi.apiKey;
const supabase = createClient(supabaseUrl, supabaseKey);

// ---- IDEMPOTENCE KEY
const idempotence_key = crypto.createHash('sha256')
  .update(`${validated_approval.approval_id}:${approved_channel}:${validated_approval.trace_id}:${validated_approval.advisory_hash}`)
  .digest('hex');

// ---- ATOMIC LOCK ACQUISITION
try {
  const { data: existingLock } = await supabase
    .from('bank_dispatch_logs')
    .select('*')
    .eq('idempotence_key', idempotence_key)
    .single();

  if (existingLock) {
    if (existingLock.status === 'dispatched') {
      throw new Error(`ALREADY_DISPATCHED: Dispatch already completed for ${idempotence_key.slice(0, 16)}`);
    }
    if (existingLock.status === 'locked') {
      // Check lock timeout (5 minutes)
      const lockAge = Date.now() - new Date(existingLock.locked_at).getTime();
      if (lockAge < 5 * 60 * 1000) {
        throw new Error(`LOCK_HELD: Dispatch already locked (${lockAge/1000}s ago) for ${idempotence_key.slice(0, 16)}`);
      }
    }
  }

  // UPSERT LOCK (ATOMIC)
  const { data: lock, error: lockError } = await supabase
    .from('bank_dispatch_logs')
    .upsert({
      idempotence_key,
      approval_id: validated_approval.approval_id,
      trace_id: validated_approval.trace_id,
      channel: approved_channel,
      status: 'locked',
      locked_at: new Date().toISOString(),
      advisory_hash: validated_approval.advisory_hash,
      retry_count: existingLock ? existingLock.retry_count + 1 : 0,
      updated_at: new Date().toISOString()
    }, {
      onConflict: 'idempotence_key'
    })
    .select()
    .single();

  if (lockError) {
    throw new Error(`LOCK_FAILED: ${lockError.message}`);
  }

  return [{
    json: {
      ...input,
      dispatch_guard: {
        idempotence_key,
        approved_channel,
        approval_id: validated_approval.approval_id,
        trace_id: validated_approval.trace_id,
        advisory_hash: validated_approval.advisory_hash,
        guard_passed: true,
        timestamp: new Date().toISOString(),
        ledger_locked: true,
        retry_count: lock.retry_count
      }
    }
  }];
} catch (error) {
  throw new Error(`DISPATCH_GUARD_FAILED: ${error.message}`);
}

const input = $json;
const { dispatch_guard, trace_id } = input;

// ---- Normalized dispatch result
const dispatch_result = {
  status: 'DELIVERED',
  channel: 'INTERNAL_UI',
  dispatch_id: `ui_${dispatch_guard.idempotence_key.slice(0, 16)}`,
  dispatched_at: new Date().toISOString(),
  internal_reference: `adv_${trace_id}`,
  idempotence_key: dispatch_guard.idempotence_key,
  approval_id: dispatch_guard.approval_id,
  advisory_hash: dispatch_guard.advisory_hash
};

return [{
  json: {
    ...input,
    dispatch_result,
    __dispatch_type: 'INTERNAL_UI'
  }
}];

// ATOMIC DISPATCH COMPLETION
const { createClient } = require('@supabase/supabase-js');

const input = $json;
const { dispatch_guard, validated_approval, terminal_state } = input;

// ---- SUPABASE CLIENT
const supabaseUrl = $credentials.supabaseApi.supabaseUrl;
const supabaseKey = $credentials.supabaseApi.apiKey;
const supabase = createClient(supabaseUrl, supabaseKey);

// ---- REJECTIONS
if (terminal_state?.type === 'REJECTED') {
  await supabase
    .from('bank_approvals')
    .update({
      state: 'rejected',
      consumed: true,
      consumed_at: new Date().toISOString()
    })
    .eq('approval_id', validated_approval.approval_id);

  return [{
    json: {
      ...input,
      dispatch_finalized: true,
      dispatch_outcome: {
        status: 'REJECTED',
        channel: 'NONE',
        approval_id: validated_approval.approval_id,
        finalized_at: new Date().toISOString()
      }
    }
  }];
}

// ---- NORMALIZE DISPATCH RESULT
let dispatch_result = input.dispatch_result || input.response;
const final_status = dispatch_result?.status === 'DELIVERED' ? 'dispatched' : 'failed';
const dispatch_id = dispatch_result?.dispatch_id || `dispatch_${Date.now()}`;

// ---- ATOMIC DISPATCH COMPLETION
const { data: updatedLock, error } = await supabase
  .from('bank_dispatch_logs')
  .update({
    status: final_status,
    dispatched_at: new Date().toISOString(),
    dispatch_id,
    dispatch_result: dispatch_result,
    updated_at: new Date().toISOString()
  })
  .eq('idempotence_key', dispatch_guard.idempotence_key)
  .eq('status', 'locked')
  .select()
  .single();

if (error || !updatedLock) {
  // Lock expired or already completed
  const { data: currentLock } = await supabase
    .from('bank_dispatch_logs')
    .select('*')
    .eq('idempotence_key', dispatch_guard.idempotence_key)
    .single();

  if (currentLock?.status === 'dispatched') {
    dispatch_result = currentLock.dispatch_result;
  } else {
    throw new Error(`DISPATCH_FAILED: ${error?.message || 'Lock not found'}`);
  }
}

// ---- UPDATE APPROVAL STATE
if (final_status === 'dispatched') {
  await supabase
    .from('bank_approvals')
    .update({
      state: 'dispatched',
      updated_at: new Date().toISOString()
    })
    .eq('approval_id', validated_approval.approval_id);
}

return [{
  json: {
    ...input,
    dispatch_finalized: true,
    dispatch_outcome: {
      status: final_status.toUpperCase(),
      channel: dispatch_guard.approved_channel,
      dispatch_id,
      approval_id: validated_approval.approval_id,
      trace_id: validated_approval.trace_id,
      finalized_at: new Date().toISOString(),
      idempotence_key: dispatch_guard.idempotence_key,
      ledger_committed: true
    }
  }
}];

// BLOCK 5 FORENSIC SEAL (FIXED - NO STATIC DATA)
const crypto = require('crypto');
const { createClient } = require('@supabase/supabase-js');

const input = $json;
const { dispatch_outcome, dispatch_guard, validated_approval, terminal_state, __block_4_complete } = input;

// ---- SUPABASE CLIENT
const supabaseUrl = $credentials.supabaseApi.supabaseUrl;
const supabaseKey = $credentials.supabaseApi.apiKey;
const supabase = createClient(supabaseUrl, supabaseKey);

// ---- BLOCK 4 SEAL VERIFICATION (FIXED TO phase_seal_hash)
if (!__block_4_complete?.phase_seal_hash) {
  throw new Error('FORENSIC_SEAL_FAILED: BLOCK 4 phase_seal_hash not found');
}

// ---- HANDLE REJECTIONS
if (terminal_state?.type === 'REJECTED') {
  const seal_data = {
    previous_block_seal_hash: __block_4_complete.phase_seal_hash, // FIXED
    approval_id: validated_approval.approval_id,
    advisory_hash: validated_approval.advisory_hash,
    trace_id: validated_approval.trace_id,
    decision: 'REJECTED',
    approver_id: validated_approval.approver_id,
    approver_role: validated_approval.approver_role,
    rejection_timestamp: terminal_state.timestamp,
    rejection_reason: terminal_state.rejection_reason,
    selected_channel: validated_approval.selected_channel,
    seal_timestamp: new Date().toISOString()
  };

  const seal_hash = crypto.createHash('sha256')
    .update(JSON.stringify(seal_data))
    .digest('hex');

  return [{
    json: {
      ...input,
      __block_5_complete: {
        sealed: true,
        seal_id: `seal_rejected_${validated_approval.approval_id}`,
        seal_hash,
        seal_data,
        sealed_at: new Date().toISOString(),
        terminal_state: true,
        bank_audit_compliant: true,
        dispatch_performed: false,
        block_4_integrity_verified: true
      }
    }
  }];
}

// ---- APPROVED DISPATCHES
const seal_data = {
  previous_block_seal_hash: __block_4_complete.phase_seal_hash, // FIXED
  approval_id: validated_approval.approval_id,
  advisory_hash: validated_approval.advisory_hash,
  trace_id: validated_approval.trace_id,
  approver_id: validated_approval.approver_id,
  approver_role: validated_approval.approver_role,
  approved_channel: validated_approval.selected_channel,
  dispatch_id: dispatch_outcome.dispatch_id,
  idempotence_key: dispatch_guard.idempotence_key,
  seal_timestamp: new Date().toISOString(),
  dispatch_status: dispatch_outcome.status,
  dispatch_performed: true,
  channel_compliance: dispatch_outcome.channel === 'EMAIL_TEMPLATE' ? {
    delivery_mechanism: 'GMAIL_OAUTH_SEND_ONLY',
    smtp_credentials_stored: false,
    replaceable_with_bank_smtp: true,
    compliance_class: 'NON_CORE_INFRASTRUCTURE'
  } : null
};

const seal_hash = crypto.createHash('sha256')
  .update(JSON.stringify(seal_data))
  .digest('hex');

// ---- UPDATE SUPABASE DISPATCH LOG (NO STATIC DATA)
await supabase
  .from('bank_dispatch_logs')
  .update({
    sealed: true,
    seal_hash
  })
  .eq('idempotence_key', dispatch_guard.idempotence_key);

return [{
  json: {
    ...input,
    __block_5_complete: {
      sealed: true,
      seal_id: `seal_dispatch_${validated_approval.approval_id}`,
      seal_hash,
      seal_data,
      sealed_at: new Date().toISOString(),
      terminal_state: true,
      bank_audit_compliant: true,
      dispatch_performed: true,
      block_4_integrity_verified: true,
      single_approval_authority: true,
      canonical_advisory_hash_used: true
    }
  }
}];

// Analytics Emitter
const input = $json;
const { dispatch_outcome, validated_approval, advisory_confidence, __block_5_complete } = input;

// ---- NON-BLOCKING ANALYTICS EMISSION
try {
  const analytics_payload = {
    event_id: `analytics_${Date.now()}_${dispatch_outcome?.dispatch_id || 'rejected'}`,
    trace_id: input.trace_id,
    dispatch_id: dispatch_outcome?.dispatch_id,
    channel: dispatch_outcome?.channel || validated_approval?.selected_channel,
    status: dispatch_outcome?.status || 'REJECTED',
    confidence_score: advisory_confidence.score,
    approver_role: validated_approval?.approver_role,
    sealed_block_id: __block_5_complete?.seal_id,
    canonical_advisory_hash: validated_approval?.advisory_hash?.slice(0, 16),
    emitted_at: new Date().toISOString(),
    analytics_class: 'NON_BLOCKING_OBSERVABILITY',
    required_for_success: false,
    authoritative: false
  };

  console.log('[ANALYTICS_EMITTED]', JSON.stringify(analytics_payload));
} catch (analyticsError) {
  console.error('[ANALYTICS_ERROR_NON_BLOCKING]', analyticsError.message);
}

return [{
  json: {
    ...input,
    analytics_emission: {
      status: 'EMITTED',
      emission_id: `analytics_${Date.now()}`,
      non_blocking: true,
      audit_compliant: true
    }
  }
}];

