// PRODUCTION VALIDATOR WITH HMAC ENFORCEMENT & HASH VERIFICATION
const crypto = require('crypto');
const { createClient } = require('@supabase/supabase-js');

const input = $json;
const approval_payload = input.body;
const stored_record = {
  approval_id: input.approval_id,
  trace_id: input.trace_id,
  approval_request: input.approval_request,
  approval_request_hash: input.approval_request_hash,
  advisory_hash: input.advisory_hash,
  selected_channel: input.selected_channel,
  request_integrity_hash: input.request_integrity_hash,
  created_at: input.created_at,
  expires_at: input.expires_at,
  consumed: input.consumed,
  state: input.state,
  block_4_seal_hash: input.block_4_seal_hash
};

console.log(`[VALIDATOR] Processing approval: ${stored_record.approval_id}`);

// === 1. ENVIRONMENT-BASED HMAC ENFORCEMENT ===
const ENVIRONMENT = $vars.ENVIRONMENT || 'development';
const isProduction = ENVIRONMENT === 'production';

// === 2. APPROVAL REQUEST HASH VERIFICATION (CRITICAL FIX 6) ===
const recomputed_approval_request_hash = crypto.createHash('sha256')
  .update(JSON.stringify(stored_record.approval_request))
  .digest('hex');

if (recomputed_approval_request_hash !== stored_record.approval_request_hash) {
  throw new Error(`IMMUTABILITY_VIOLATION: Approval request hash mismatch`);
}

// === 3. EXPIRY ENFORCEMENT ===
const now = new Date();
const expiresAt = new Date(stored_record.expires_at);

if (now > expiresAt) {
  throw new Error(`APPROVAL_EXPIRED: Approval expired at ${stored_record.expires_at}`);
}

// === 4. REQUIRED FIELDS ===
const REQUIRED_FIELDS = [
  'approval_id', 'decision', 'approver_id', 'approver_role',
  'approval_timestamp', 'advisory_hash', 'trace_id'
];

for (const field of REQUIRED_FIELDS) {
  if (!approval_payload[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// === 5. CROSS-VALIDATION ===
if (stored_record.approval_id !== approval_payload.approval_id) {
  throw new Error('approval_id mismatch');
}

if (stored_record.advisory_hash !== approval_payload.advisory_hash) {
  throw new Error('advisory_hash mismatch');
}

// === 6. HMAC VALIDATION (FIX 1) ===
let hmac_valid = false;

if (isProduction) {
  if (!approval_payload.approval_hmac) {
    throw new Error('HMAC_REQUIRED: Approval HMAC is required in production');
  }

  const BANK_HMAC_SECRET = $vars.BANK_HMAC_SECRET;
  if (!BANK_HMAC_SECRET) {
    throw new Error('HMAC_SECRET_MISSING: BANK_HMAC_SECRET not configured');
  }

  const hmac_data = `${approval_payload.approval_id}:${approval_payload.advisory_hash}:${approval_payload.trace_id}:${approval_payload.approver_id}:${approval_payload.approval_timestamp}:${approval_payload.decision}:${stored_record.selected_channel}`;

  const expected_hmac = crypto.createHmac('sha256', BANK_HMAC_SECRET)
    .update(hmac_data)
    .digest('hex');

  hmac_valid = (approval_payload.approval_hmac === expected_hmac);

  if (!hmac_valid) {
    throw new Error('HMAC_VALIDATION_FAILED: Invalid approval HMAC');
  }
} else {
  console.warn('[DEV_MODE] Skipping HMAC validation');
  hmac_valid = approval_payload.approval_hmac ? true : false;
}

// === 7. VALIDATED OUTPUT ===
const validated_approval = {
  ...approval_payload,
  selected_channel: stored_record.selected_channel, // FROM LEDGER
  validated_at: now.toISOString(),
  approval_age_seconds: (now - new Date(stored_record.created_at)) / 1000,
  expiry_verified: true,
  hmac_valid,
  approval_request_hash_verified: true,
  validator_version: '4.0-production'
};

return [{
  json: {
    validated_approval,
    approval_request: stored_record.approval_request,
    validation_result: {
      status: 'VALIDATED',
      timestamp: now.toISOString(),
      environment: ENVIRONMENT,
      hmac_enforced: isProduction,
      hmac_valid
    }
  }
}];

const crypto = require('crypto');

const BANK_HMAC_SECRET = $vars.BANK_HMAC_SECRET;
if (!BANK_HMAC_SECRET) {
  throw new Error('BANK_HMAC_SECRET not configured');
}

const approval_id = "approval_267_9317428e-83ac-4106-ab0b-ef30edd4c73a";
const advisory_hash = "99415823b031a4426c56c4efff40f764007b7e27359c43b26c18904ebf2cf668";
const trace_id = "267";
const approver_id = "system_bot_001";
const approval_timestamp = "2026-01-03T10:40:00.000Z";
const decision = "APPROVED";
const selected_channel = "EMAIL_TEMPLATE";

const hmac_data = `${approval_id}:${advisory_hash}:${trace_id}:${approver_id}:${approval_timestamp}:${decision}:${selected_channel}`;

const hmac = crypto.createHmac('sha256', BANK_HMAC_SECRET)
  .update(hmac_data)
  .digest('hex');

const curlCommand = `curl -X POST "https://revenant18.app.n8n.cloud/webhook-test/0c2a1910-9883-48cd-8d52-301d6476a209" \\
  -H "Content-Type: application/json" \\
  -d '{\
    \"approval_id\": \"${approval_id}\",\n    \"decision\": \"${decision}\",\n    \"approver_id\": \"${approver_id}\",\n    \"approver_role\": \"risk_officer\",\n    \"approval_timestamp\": \"${approval_timestamp}\",\n    \"advisory_hash\": \"${advisory_hash}\",\n    \"approval_hmac\": \"${hmac}\",\n    \"trace_id\": \"${trace_id}\"\n  }'`;

console.log("HMAC:", hmac);
console.log("CURL:", curlCommand);

return {
  hmac,
  curlCommand
};
